                      char* g_updating_graph_mask,
                      char* g_graph_visited,
                      char* g_over,
                      const int no_of_nodes) {
    int tid = threadIdx.x + blockIdx.x * blockDim.x;
    if (tid < no_of_nodes && g_updating_graph_mask[tid]) {
        g_graph_mask[tid] = true;
        g_graph_visited[tid] = true;
