int divRndUp(int n, 
             int d)
{
    return (n / d) + ((n % d) ? 1 : 0);
}













void storeComponents(int *d_r,   
                     int *d_g,
                     int *d_b,
                     int r,
                     int g,
                     int b,
                     int pos)
{
