void launchFDWT53Kernel (int WIN_SX, int WIN_SY, cudaMemory_t in, cudaMemory_t out, int sx, int sy)
{




    const int steps = ( sy/ (15 * WIN_SY)) + ((sy % (15 * WIN_SY)) ? 1 : 0);	

	int gx = ( sx/ WIN_SX) + ((sx %  WIN_SX) ? 1 : 0);  
	int gy = ( sy/ (WIN_SY*steps)) + ((sy %  (WIN_SY*steps)) ? 1 : 0);

	printf("sliding steps = %d , gx = %d , gy = %d \n", steps, gx, gy);


	size_t globalWorkSize[2] = { gx*WIN_SX, gy*1};
    size_t localWorkSize[2]  = { WIN_SX , 1};


	errNum  = cudaFuncSetArg(kl_fdwt53Kernel, 0, sizeof(cudaMemory_t), &in);
	errNum |= cudaFuncSetArg(kl_fdwt53Kernel, 1, sizeof(cudaMemory_t), &out);
	errNum |= cudaFuncSetArg(kl_fdwt53Kernel, 2, sizeof(int), &sx);
	errNum |= cudaFuncSetArg(kl_fdwt53Kernel, 3, sizeof(int), &sy);
	errNum |= cudaFuncSetArg(kl_fdwt53Kernel, 4, sizeof(int), &steps);
	errNum |= cudaFuncSetArg(kl_fdwt53Kernel, 5, sizeof(int), &WIN_SX);
	errNum |= cudaFuncSetArg(kl_fdwt53Kernel, 6, sizeof(int), &WIN_SY);


	errNum = cudaLaunchKernel(commandQueue, kl_fdwt53Kernel, 2, NULL, globalWorkSize, localWorkSize, 0, NULL, NULL);

	printf("kl_fdwt53Kernel in launchFDW53Kernel has finished\n");


}








void memCopy (cudaMemory_t dest,  cudaMemory_t src, const size_t sx, const size_t sy){

	errNum = cudaMemcpyAsync (commandQueue, dest, src, sx*sy*sizeof(int), cudaMemcpyDeviceToDevice);


}












void fdwt53(cudaMemory_t in, cudaMemory_t out, int sizeX, int sizeY, int levels)
{


    if(sizeX >= 960) 
	{
      launchFDWT53Kernel(192, 8, in, out, sizeX, sizeY);
    } 
	else if (sizeX >= 480) 
	{
      launchFDWT53Kernel(128, 8, in, out, sizeX, sizeY);
    } else 
	{
      launchFDWT53Kernel(64, 8, in, out, sizeX, sizeY);
	}


	if (levels > 1)
	{

		const int llSizeX = (sizeX / 2) + ((sizeX % 2) ? 1 :0);
		const int llSizeY = (sizeY / 2) + ((sizeY % 2) ? 1 :0);
		memCopy(in, out, llSizeX, llSizeY);


		fdwt53(in, out, llSizeX, llSizeY, levels - 1);
	}	
}




