    int writeVisual = 0;
    char input_dir[100] = { "." };
    char *pos;

    while ((ch = getopt_long(argc, argv, "d:p:c:b:l:i:D:fr95wh", longopts, &optindex)) != -1)
    {
        switch (ch)
        {
        case 'D':
            pixWidth = atoi(optarg);
            pos = strstr(optarg, "x");
            if (pos == NULL || pixWidth == 0 || (strlen(pos) >= strlen(optarg)))
            {
                usage();
                return -1;
            }
            pixHeight = atoi(pos + 1);
            break;
        case 'c':
            compCount = atoi(optarg);
            break;
        case 'b':
            bitDepth = atoi(optarg);
            break;
        case 'l':
            dwtLvls = atoi(optarg);
            break;
        case 'd':
            break;
        case 'p':
            break;
        case 'i':
            strcpy(input_dir, optarg);
            break;
        case 'f':
            forward = 1;
            break;
        case 'r':
            forward = 0;
            break;
        case '9':
            dwt97 = 1;
            break;
        case '5':
            dwt97 = 0;
            break;
        case 'w':
            writeVisual = 1;
            break;
        case 'h':
            usage();
            return 0;
        case '?':
            return -1;
        default:
            usage();
            return -1;
        }
    }
    argc -= optindex;
    argv += optindex;

    if (argc == 0)
    {
        printf("Please supply src file name\n");
        usage();
        return -1;
    }

    if (pixWidth <= 0 || pixHeight <= 0)
    {
        printf("Wrong or missing dimensions\n");
        usage();
        return -1;
    }

