    strcpy(d->srcFilename, argv[0]);
    if (argc == 1)
    {
        d->outFilename = (char *)malloc(strlen(d->srcFilename) + 4);
        strcpy(d->outFilename, d->srcFilename);
        strcpy(d->outFilename + strlen(d->srcFilename), ".dwt");
    }
    else
    {
