__global__ void Fan1_cuda(float *m_dev,
                  float *a_dev,
                  float *b_dev,
                  const int size,
                  const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (globalId < size-1-t) {
         *(m_dev + size * (globalId + t + 1)+t) = *(a_dev + size * (globalId + t + 1) + t) / *(a_dev + size * t + t);    
    }
}

__global__ void Fan2_cuda(float *m_dev,
                  float *a_dev,
                  float *b_dev,
                  const int size,
                  const int t) {
	 int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
	 int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;
      if (globalIdx < size-1-t && globalIdy < size-t) {
         a_dev[size*(globalIdx+1+t)+(globalIdy+t)] -= m_dev[size*(globalIdx+1+t)+t] * a_dev[size*t+(globalIdy+t)];

 	    if(globalIdy == 0){
 		   b_dev[globalIdx+1+t] -= m_dev[size*(globalIdx+1+t)+(globalIdy+t)] * b_dev[t];
 	    }
 	 }
}

void cudaErrorCheck(cudaError_t error, const char *msg, bool exitOnErr) {
    if(error != cudaSuccess) {
        printf("CUDA Error: %d %s %s\n", error, cudaGetErrorString(error), msg);
        if(exitOnErr) {
            exit(-1);
        }
    }
}

void create_matrix(float *m, int size){
  int i,j;
  float lamda = -0.01;
  float coe[2*size-1];
  float coe_i =0.0;

  for (i=0; i < size; i++)
    {
      coe_i = 10*exp(lamda*i); 
      j=size-1+i;     
      coe[j]=coe_i;
      j=size-1-i;     
      coe[j]=coe_i;
    }

  for (i=0; i < size; i++) {
      for (j=0; j < size; j++) {
	m[i*size+j]=coe[size-1-i+j];
      }
  }
}

void InitPerRun(int size, float *m) {
    int i;
    for (i=0; i<size*size; i++)
        *(m+i) = 0.0;
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    int i,j;
    for(i=0;i<size;i++){
        finalVec[size-i-1]=b[size-i-1];
        for(j=0;j<i;j++) {
            finalVec[size-i-1]-=*(a+size*(size-i-1)+(size-j-1)) * finalVec[size-j-1];
        }
        finalVec[size-i-1]=finalVec[size-i-1]/ *(a+size*(size-i-1)+(size-i-1));
    }
}

void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    int i, j;
    for (i=0; i<nrow; i++) {
        for (j=0; j<ncol; j++) {
            fscanf(fp, "%f",  ary+size*i+j);
        }
    }  
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    int i;
    for (i=0; i<ary_size; i++) {
        fscanf(fp, "%f",  &ary[i]);
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    int i, j;
    for (i=0; i<nrow; i++) {
        for (j=0; j<ncol; j++) {
            printf("%8.2e ", *(ary+size*i+j));
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    int i;
    for (i=0; i<ary_size; i++) {
        printf("%.2e ", ary[i]);
    }
    printf("\n\n");
}

void ForwardSub_cuda(float *a, float *b, float *m, int size, int timing){    
    cudaError_t status=0;
    float writeMB=0,readMB=0;

    float *a_dev, *b_dev, *m_dev;

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    status = cudaMalloc(&a_dev, sizeof(float)*size*size);
    cudaErrorCheck(status, "cudaMalloc a_dev", true);
    status = cudaMalloc(&b_dev, sizeof(float)*size);
    cudaErrorCheck(status, "cudaMalloc b_dev", true);
    status = cudaMalloc(&m_dev, sizeof(float)*size*size);
    cudaErrorCheck(status, "cudaMalloc m_dev", true);
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    status = cudaMemcpy(a_dev, a, sizeof(float)*size*size, cudaMemcpyHostToDevice);
    cudaErrorCheck(status, "cudaMemcpy a_dev", true);
    status = cudaMemcpy(b_dev, b, sizeof(float)*size, cudaMemcpyHostToDevice);
    cudaErrorCheck(status, "cudaMemcpy b_dev", true);
    status = cudaMemcpy(m_dev, m, sizeof(float)*size*size, cudaMemcpyHostToDevice);
    cudaErrorCheck(status, "cudaMemcpy m_dev", true);
#ifdef  TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    writeMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

    dim3 blockDimFan1(BLOCK_SIZE_0, 1, 1);
    dim3 blockDimFan2(BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y, 1);

    int t;
    for (t=0; t<(size-1); t++) {
#ifdef  TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        int globalWorksizeFan1 = size;
        Fan1_cuda<<<(globalWorksizeFan1 + BLOCK_SIZE_0 - 1) / BLOCK_SIZE_0, blockDimFan1>>>(m_dev, a_dev, b_dev, size, t);
        status = cudaDeviceSynchronize();
        cudaErrorCheck(status, "Fan1 cudaDeviceSynchronize", true);
#ifdef  TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        dim3 dimGridFan2((size + BLOCK_SIZE_1_X - 1) / BLOCK_SIZE_1_X, (size + BLOCK_SIZE_1_Y - 1) / BLOCK_SIZE_1_Y, 1);
        Fan2_cuda<<<dimGridFan2, blockDimFan2>>>(m_dev, a_dev, b_dev, size, t);
        status = cudaDeviceSynchronize();
        cudaErrorCheck(status, "Fan2 cudaDeviceSynchronize", true);
#ifdef  TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
    }

#ifdef  TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    status = cudaMemcpy(a, a_dev, sizeof(float)*size*size, cudaMemcpyDeviceToHost);
    cudaErrorCheck(status, "cudaMemcpy a", true);
    status = cudaMemcpy(b, b_dev, sizeof(float)*size, cudaMemcpyDeviceToHost);
    cudaErrorCheck(status, "cudaMemcpy b", true);
    status = cudaMemcpy(m, m_dev, sizeof(float)*size*size, cudaMemcpyDeviceToHost);
    cudaErrorCheck(status, "cudaMemcpy m", true);
#ifdef  TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    readMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

#ifdef TIMING
    printf("Matrix Size\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
    printf("%dx%d      \t",size,size);
    printf("%f [%.2fMB]\t",h2d_time,writeMB);
    printf("%f\t",kernel_time);
    printf("%f [%.2fMB]\t",d2h_time,readMB);
    printf("%f\n\n",h2d_time+kernel_time+d2h_time);
#endif

#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cudaFree(a_dev);
    cudaFree(b_dev);
    cudaFree(m_dev);
#ifdef  TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
}

void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *result) {
    result->tv_sec = t1->tv_sec - t2->tv_sec;
    result->tv_usec = t1->tv_usec - t2->tv_usec;
    if (result->tv_usec < 0) {
        result->tv_sec--;
        result->tv_usec += 1000000;
    }
}

