	membership_OCL = (int*) malloc(n_points * sizeof(int));
}

void deallocateMemory()
{
#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif
	cudaFree(d_feature);
	cudaFree(d_feature_swap);
	cudaFree(d_cluster);
