using namespace std;

// Data structures
typedef struct latLong {
    float lat;
    float lng;
} LatLong;

typedef struct record {
    char recString[49];
    float distance;
} Record;

// CUDA kernel for nearest neighbor calculation
__global__ void NearestNeighbor(LatLong *d_locations,
                                float *d_distances,
                                const int numRecords,
                                const float lat,
                                const float lng) {
    int globalId = threadIdx.x + blockDim.x * blockIdx.x;

    if (globalId < numRecords) {
        LatLong *latLong = d_locations + globalId;
        float *dist = d_distances + globalId;
        *dist = sqrtf((lat - latLong->lat) * (lat - latLong->lat) + 
                      (lng - latLong->lng) * (lng - latLong->lng));
    }
}

// CUDA utility functions
static cudaDeviceProp deviceProp;
static int cudaDevice = 0;
static bool eventsEnabled = false;

int cuda_init(char devicePreference) {
    int deviceCount;
    cudaGetDeviceCount(&deviceCount);

    if (deviceCount == 0) {
        printf("No CUDA devices found\n");
        exit(-1);
    }

    for (int i = 0; i < deviceCount; i++) {
        cudaGetDeviceProperties(&deviceProp, i);
        printf("Device %d:\n", i);
        printf("\tName: %s\n", deviceProp.name);
        printf("\tVendor: NVIDIA\n");
    }

    cudaDevice = 0;
    printf("Using Device %d\n", cudaDevice);

    cudaSetDevice(cudaDevice);

    return cudaDevice;
}

int cuda_init_context(int platform, int dev, int quiet) {
    int printInfo = 1;
    if (platform >= 0 && dev >= 0) printInfo = 0;

    int deviceCount;
    cudaGetDeviceCount(&deviceCount);

    if (printInfo) {
        printf("Number of CUDA devices detected: %d\n", deviceCount);
        printf("Checking For CUDA Compatible Devices\n");
    }

    for (int i = 0; i < deviceCount; i++) {
        cudaGetDeviceProperties(&deviceProp, i);
        if (printInfo) {
            printf("Device %d:\t", i);
            printf("Name: %s\n", deviceProp.name);
        }
    }

    int device_touse;
    if (printInfo) {
        printf("Enter Device No\n");
        scanf("%d", &device_touse);
    } else {
        device_touse = dev;
    }

    if (device_touse >= deviceCount) {
        printf("Invalid Device Number\n");
        exit(1);
    }

    if (!quiet) printf("Using Device No %d\n", device_touse);

    cudaSetDevice(device_touse);
    cudaDevice = device_touse;

    return cudaDevice;
}

void cuda_cleanup() {
