    }
    else {
        usage(argc, argv);
    }

    if (atoi(argv[1]) % 16 != 0) {
        fprintf(stderr, "The dimension values must be a multiple of 16\n");
        exit(1);
    }

    max_rows = max_rows + 1;
    max_cols = max_cols + 1;

