#include <cuda_runtime.h>
#include <device_launch_parameters.h>

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

__global__ void memset_kernel(char * mem_d, short val, int number_bytes){
	const int thread_id = threadIdx.x + blockIdx.x * blockDim.x;
	if(thread_id < number_bytes)
	  mem_d[thread_id] = val;
}

__global__ void pgain_kernel(
			 Point_Struct *p,			 
			 float *coord_d,
			 float * work_mem_d,			
			 int *center_table_d,
			 char *switch_membership_d,			
			 int num,
			 int dim,
			 long x,
			 int K){	

	const int thread_id = threadIdx.x + blockIdx.x * blockDim.x;
	const int local_id = threadIdx.x;

	if(thread_id<num){

	  __shared__ float coord_s[256];

	  if(local_id == 0)
	   	for(int i=0; i<dim; i++){ 
	   		coord_s[i] = coord_d[i*num + x];
	   	}
	  __syncthreads();


	  float x_cost = 0.0;
	  for(int i=0; i<dim; i++)
		  x_cost += (coord_d[(i*num)+thread_id]-coord_s[i]) * (coord_d[(i*num)+thread_id]-coord_s[i]);
	  x_cost = x_cost * p[thread_id].weight;

	  float current_cost = p[thread_id].cost;

	  int base = thread_id*(K+1);	 

	  if ( x_cost < current_cost ){
		  switch_membership_d[thread_id] = '1';
	      int addr_1 = base + K;
	      work_mem_d[addr_1] = x_cost - current_cost;
	  }

	  else {
	      int assign = p[thread_id].assign;
	      int addr_2 = base + center_table_d[assign];
	      work_mem_d[addr_2] += current_cost - x_cost;
	  }
	}
}

